      <CustomCursor />

      <Navbar scrollProgress={scrollProgress} />

      <main>
        <Hero />

        <div className="container mx-auto px-6">
          <div className="h-px w-full bg-gradient-to-r from-transparent via-[#8F62AA] to-transparent opacity-30 shadow-[0_0_10px_#8F62AA]" />
