import React, { useState, useRef, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { MessageSquare, X, Send, Cpu, Sparkles } from 'lucide-react';
import { GoogleGenAI } from "@google/genai";

const NeuralAssistant: React.FC = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<{ role: 'user' | 'ai', content: string }[]>([
    { role: 'ai', content: "Neural Interface Online. I am the Tathastu Growth Oracle. State your brand objective or query the data banks." }
  ]);
  const [isTyping, setIsTyping] = useState(false);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [messages, isTyping]);

  const handleSend = async () => {
    if (!input.trim() || isTyping) return;

    const userMsg = input.trim();
    setInput('');
    setMessages(prev => [...prev, { role: 'user', content: userMsg }]);
    setIsTyping(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const response = await ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: userMsg,
        config: {
          systemInstruction: "You are the Tathastu Digital Neural Interface. You are a cold, high-tech, yet helpful growth AI. Your tone is futuristic, minimalist, and authoritative. You provide ultra-practical marketing advice focused on 'systems', 'ecosystems', and 'leverage'. Keep responses concise (under 3 sentences).",
          temperature: 0.7,
        },
      });

      const aiText = response.text || "Connection interrupted. Re-initializing...";
      setMessages(prev => [...prev, { role: 'ai', content: aiText }]);
    } catch (error) {
      setMessages(prev => [...prev, { role: 'ai', content: "Neural lag detected. Error 404: Growth logic not found." }]);
    } finally {
      setIsTyping(false);
    }
  };

  return (
    <div className="fixed bottom-8 right-8 z-[100] pointer-events-auto">
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, scale: 0.9, y: 20 }}
            animate={{ opacity: 1, scale: 1, y: 0 }}
            exit={{ opacity: 0, scale: 0.9, y: 20 }}
            className="absolute bottom-20 right-0 w-[350px] md:w-[400px] h-[500px] glass-panel rounded-3xl overflow-hidden border-[#8F62AA]/30 flex flex-col shadow-[0_0_50px_rgba(143,98,170,0.2)]"
          >
            {/* Header */}
            <div className="p-4 border-b border-white/10 bg-[#8F62AA]/10 flex justify-between items-center">
              <div className="flex items-center gap-2">
                <div className="w-2 h-2 rounded-full bg-[#8F62AA] animate-pulse" />
                <span className="font-mono text-xs tracking-widest text-white/80 uppercase">Neural_Consultant_v2.5</span>
              </div>
              <button onClick={() => setIsOpen(false)} className="text-white/40 hover:text-white">
                <X size={18} />
              </button>
            </div>

            {/* Messages */}
            <div ref={scrollRef} className="flex-1 overflow-y-auto p-4 space-y-4 no-scrollbar">
              {messages.map((m, i) => (
                <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                  <div className={`max-w-[85%] p-3 rounded-2xl text-sm leading-relaxed ${
                    m.role === 'user' 
                      ? 'bg-[#8F62AA]/20 border border-[#8F62AA]/30 text-white rounded-tr-none' 
                      : 'bg-white/5 border border-white/10 text-white/80 rounded-tl-none'
                  }`}>
                    {m.content}
                  </div>
                </div>
              ))}
              {isTyping && (
                <div className="flex justify-start">
                  <div className="bg-white/5 border border-white/10 p-3 rounded-2xl rounded-tl-none">
                    <div className="flex gap-1">
                      <div className="w-1.5 h-1.5 bg-[#8F62AA] rounded-full animate-bounce" />
                      <div className="w-1.5 h-1.5 bg-[#8F62AA] rounded-full animate-bounce [animation-delay:0.2s]" />
                      <div className="w-1.5 h-1.5 bg-[#8F62AA] rounded-full animate-bounce [animation-delay:0.4s]" />
                    </div>
                  </div>
                </div>
              )}
            </div>

            {/* Input */}
            <div className="p-4 bg-white/5 border-t border-white/10">
              <div className="relative">
                <input 
                  type="text" 
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleSend()}
                  placeholder="Ask the Oracle..."
                  className="w-full bg-white/5 border border-white/10 rounded-xl px-4 py-3 text-sm focus:outline-none focus:border-[#8F62AA]/50 transition-all placeholder:text-white/20 pr-12"
                />
                <button 
                  onClick={handleSend}
                  disabled={isTyping}
                  className="absolute right-2 top-1/2 -translate-y-1/2 w-8 h-8 rounded-lg bg-[#8F62AA]/20 hover:bg-[#8F62AA] flex items-center justify-center transition-all group"
                >
                  <Send size={14} className="group-hover:scale-110 transition-transform" />
                </button>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <motion.button
        onClick={() => setIsOpen(!isOpen)}
        whileHover={{ scale: 1.1 }}
        whileTap={{ scale: 0.9 }}
        className={`w-14 h-14 rounded-full flex items-center justify-center shadow-[0_0_20px_rgba(143,98,170,0.4)] border border-[#8F62AA]/50 transition-all ${
          isOpen ? 'bg-white text-[#8F62AA]' : 'bg-[#8F62AA] text-white'
        }`}
      >
        <Sparkles size={24} className={isOpen ? '' : 'animate-pulse'} />
      </motion.button>
    </div>
  );
};

